import{_ as n,o as s,c as t,an as a}from"./chunks/framework.D5fFzH9V.js";const i="/assets/f7db67bef6420d59c3fbd2f8f3ac19d4.png",r="/assets/f253d6b64a48b65510d5f3ee4575b304.png",d="/assets/9688e49730402e608f3c7af6fa045eca.png",o="/assets/bd55fdeea6c643a87c85ac47b4af94da.png",b=JSON.parse('{"title":"Andere Lösungsvorschläge?","description":"Wie der Microsoft-Teams-Status (Presence) sensible Gewohnheiten preisgeben kann und welche Admin-Optionen die Sichtbarkeit für Externe reduzieren.","frontmatter":{"description":"Wie der Microsoft-Teams-Status (Presence) sensible Gewohnheiten preisgeben kann und welche Admin-Optionen die Sichtbarkeit für Externe reduzieren."},"headers":[],"relativePath":"de/microsoft-teams-status-disclosure.md","filePath":"de/microsoft-teams-status-disclosure.md"}'),c={name:"de/microsoft-teams-status-disclosure.md"};function u(l,e,h,f,m,p){return s(),t("div",null,[...e[0]||(e[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de/microsoft-teams-status-disclosure.md for this page in Markdown format</div><h2 id="microsoft-teams-status-disclosure" tabindex="-1">Microsoft Teams Status Disclosure <a class="header-anchor" href="#microsoft-teams-status-disclosure" aria-label="Permalink to &quot;Microsoft Teams Status Disclosure&quot;">​</a></h2><p>Das &quot;Status-Lämpchen&quot; von MS-Teams ist ziemlich unscheinbar, verrät aber ganz schön viel über dich und deine Gewohnheiten. Wann du zu arbeiten beginnst und wann du aufhörst, ob du gerade mit deinen Kollegen auf Kaffeepause bist, dich in einem Meeting berieseln lässt oder selber gerade in diesem Augenblick präsentierst.</p><p>Statusinformationen mögen in einer Organisation vielleicht ganz nützlich sein, standardmäßig können allerdings auch alle außerhalb deiner Organisation deinen Anwesenheitsstatus sehen. Uns ist aufgefallen, dass das bei vielen unserer Kontakte der Fall ist.</p><p><img src="'+i+'" alt="f7db67bef6420d59c3fbd2f8f3ac19d4.png"></p><h2 id="behebung" tabindex="-1">Behebung <a class="header-anchor" href="#behebung" aria-label="Permalink to &quot;Behebung&quot;">​</a></h2><p>Wenn du das nicht möchtest, muss die Standardkonfiguration im Teams Admin Center angepasst werden. Doch eines vorweg: leider gibt es keine Möglichkeit, den Zugriff auf Statusinformationen für Externe vollständig zu deaktivieren.</p><p>Du hast jedoch die folgenden Optionen den Zugriff zu verhindern, wenn auch mit Einschränkungen:</p><p>Option 1) du aktivierst den Skype4Business Presence Privacy Mode. Diese Option schränkt den Zugriff auf Anwesenheitsinformationen auf Skype4Business- oder Teams-Kontakte auf deine persönliche Kontaktliste ein.</p><p><img src="'+r+'" alt="f253d6b64a48b65510d5f3ee4575b304.png"></p><p>Option 2) du blockierst alle externen Domänen. Damit können deine Kollegen außerhalb deiner Organisation niemanden suchen, mit ihm telefonieren, chatten oder Meetings führen. Der Austausch mit anderen ist dann nur noch über einen Gastzugriff möglich.</p><p><img src="'+d+'" alt="9688e49730402e608f3c7af6fa045eca.png"></p><p>Wenn ihr schon dabei seid MS-Teams zu härten, solltet ihr außerdem die Option deaktivieren, die es Personen erlaubt mit Skype-Usern zu kommunizieren.</p><p><img src="'+o+'" alt="bd55fdeea6c643a87c85ac47b4af94da.png"></p><h1 id="andere-losungsvorschlage" tabindex="-1">Andere Lösungsvorschläge? <a class="header-anchor" href="#andere-losungsvorschlage" aria-label="Permalink to &quot;Andere Lösungsvorschläge?&quot;">​</a></h1><p>Geht das besser? Habt ihr Feedback?</p><p><a href="/contact-us">Schreibt uns!</a></p>',17)])])}const k=n(c,[["render",u]]);export{b as __pageData,k as default};
